module RefModule(
    input clk,
    input reset,
    output reg [4:0] q
);

      wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
        if (reset) begin
            // Synchronous reset
            q <= 5'b00001;
        end else begin
            // Ring counter logic
            q <= {q[3:0], q[4]};
        end
    end

endmodule
